<?php
 declare(strict_types=1); namespace tapmeppe\composer\summons; class HtAccess extends \tapmeppe\composer\helpers\Summon { function process(array $arguments) { $start = '### governance - start'; $end = '### governance - end'; $template = sprintf( "%s\n%s\n%s", $start, trim(file_get_contents("$this->root/assets/.htaccess.template")), $end ); $target = ABSPATH . '.htaccess'; file_put_contents( $target, file_exists($target) ? (($content = file_get_contents($target)) && str_contains($content, $start) ? preg_replace("/$start(.|\s)*$end/", $template, $content) : "$template\n\n$content" ) : $template ); } } 